import json, pandas as pd

MAP = {
    'user_id':'user_id','id':'user_id','userId':'user_id',
    'email':'email','email_address':'email',
    'full_name':'name','name':'name','userName':'name',
    'registration_date':'created_date','created_at':'created_date','joined':'created_date',
    'status':'status',
}

def norm(rec):
    out={}
    for k,v in rec.items():
        if k in MAP:
            out[MAP[k]]=v
    return out

# source_a json
with open('/data/source_a/users.json') as f:
    a=[norm(r) for r in json.load(f)]
# source_b csv
b=[norm(r) for r in pd.read_csv('/data/source_b/users.csv').to_dict('records')]
# source_c parquet
c=[norm(r) for r in pd.read_parquet('/data/source_c/users.parquet').to_dict('records')]

def fmt_date(v):
    if v is None or (isinstance(v,float) and pd.isna(v)):
        return None
    return str(pd.to_datetime(str(v)).date())

def clean(rec):
    r=dict(rec)
    if 'user_id' in r and r['user_id'] is not None:
        r['user_id']=int(r['user_id'])
    if 'created_date' in r:
        r['created_date']=fmt_date(r['created_date'])
    for k,v in list(r.items()):
        if isinstance(v,float) and pd.isna(v):
            r[k]=None
        elif v is not None and k not in ('user_id',):
            r[k]=str(v) if not isinstance(v,str) else v
    return r

src={'source_a':{}, 'source_b':{}, 'source_c':{}}
for name,data in [('source_a',a),('source_b',b),('source_c',c)]:
    for rec in data:
        rec=clean(rec)
        uid=rec.get('user_id')
        if uid is None: continue
        src[name][uid]=rec

prio=['source_a','source_b','source_c']
all_ids=sorted(set().union(*[set(s) for s in src.values()]))
fields=['name','email','created_date','status']

merged=[]
conflicts=[]
for uid in all_ids:
    row={'user_id':uid}
    for field in fields:
        vals={}
        for s in prio:
            if uid in src[s] and field in src[s][uid] and src[s][uid][field] is not None:
                vals[s]=src[s][uid][field]
        if not vals:
            row[field]=None
            continue
        selected=next(vals[s] for s in prio if s in vals)
        row[field]=selected
        if len(set(vals.values()))>1:
            conflicts.append({'user_id':uid,'field':field,'values':vals,'selected':selected})
    merged.append(row)

df=pd.DataFrame(merged,columns=['user_id','name','email','created_date','status'])
df['user_id']=df['user_id'].astype('int64')
for col in ['name','email','created_date','status']:
    df[col]=df[col].astype('object')
df.to_parquet('/app/merged_users.parquet',index=False)

report={'total_conflicts':len(conflicts),'conflicts':conflicts}
with open('/app/conflicts.json','w') as f:
    json.dump(report,f,indent=2)
print(df.to_string())
print('conflicts',len(conflicts))
